+    if ((1.0 == ph_->getProtocolVersion()) || (id_list_.empty()))
+        return COMM_NOT_AVAILABLE;
+
+    int count = id_list_.size();
+    int result = COMM_RX_FAIL;
+    uint8_t *rxpacket = (uint8_t *)malloc(RXPACKET_MAX_LEN);
+    if (NULL == rxpacket)
