+            PrintErrorCode_Protocol1(dxl_error);
+            return 0;
+        }
+    }
+    else
+    {
+        PrintCommStatus(dxl_comm_result);
+        return 0;
+    }
+    printf("DXL#%d successfully connected\n", DXL2_ID);
