+    {
+        if(dxl_error != 0)
+        {
+            PrintErrorCode_Protocol1(dxl_error);
+            return 0;
+        }
+    }
+    else
+    {
+        PrintCommStatus(dxl_comm_result);
+        return 0;
+    }
+
+    // Close port
+    portHandler->ClosePort();
+
+    printf( "Press Enter key to terminate...\n" );
+    _getch();
+    return 0;
+}

