+#define BAUDRATE                        1000000
+#define DEVICENAME                      "/dev/ttyUSB0"
+
+#define STOP_MOVING_MARGIN              20                  // Criteria for considering DXL moving status as stopped
+
+using namespace ROBOTIS;
+
+#ifdef __linux__
