+        break;
+
+    case COMM_TX_FAIL:
+        printf("COMM_TXFAIL: Failed transmit instruction packet!\n");
+        break;
+
+    case COMM_RX_FAIL:
+        printf("COMM_RXFAIL: Failed get status packet from device!\n");
+        break;
+
+    case COMM_TX_ERROR:
+        printf("COMM_TXERROR: Incorrect instruction packet!\n");
+        break;
+
